const QUESTIONS_CISM_C4 = [
  { id:10641, domain:4, level:1, question:"What is the PRIMARY purpose of an incident response plan?", options:["A To assign blame for security failures","B To provide structured guidance for responding to security incidents","C To satisfy regulatory requirements","D To document all security incidents"], correct:1, explanation:"An incident response plan provides structured, predefined procedures to guide the organization through detecting, containing, and recovering from security incidents efficiently." },
  { id:10642, domain:4, level:1, question:"Which of the following BEST describes a security incident?", options:["A Any event that is logged by a security system","B scheduled maintenance window that affects system availability","C vulnerability discovered during a penetration test","D An event that actually or potentially jeopardizes the confidentiality, integrity, or availability of information"], correct:3, explanation:"A security incident is defined as an event that actually or potentially violates the CIA triad, distinguishing it from routine events or vulnerabilities not yet exploited." },
  { id:10643, domain:4, level:1, question:"What is the FIRST step in the incident response lifecycle?", options:["A Preparation","B Detection and Analysis","C Eradication","D Containment"], correct:0, explanation:"Preparation is the first phase of the incident response lifecycle, establishing the policies, procedures, tools, and training needed before an incident occurs." },
  { id:10644, domain:4, level:1, question:"Which team is PRIMARILY responsible for coordinating an organization's response to a security incident?", options:["A Human Resources","B Help Desk","C Legal Department","D Computer Security Incident Response Team (CSIRT)"], correct:3, explanation:"A CSIRT is specifically chartered to coordinate detection, analysis, containment, eradication, and recovery activities during a security incident." },
  { id:10645, domain:4, level:1, question:"What does RTO stand for in the context of business continuity?", options:["A Risk Transfer Option","B Real-Time Operations","C Regulatory Testing Order","D Recovery Time Objective"], correct:3, explanation:"Recovery Time Objective (RTO) is the maximum acceptable time within which a business process must be restored after a disruption." },
  { id:10646, domain:4, level:1, question:"What does RPO stand for in the context of disaster recovery?", options:["A Risk Priority Order","B Regulatory Process Oversight","C Remote Patching Operation","D Recovery Point Objective"], correct:3, explanation:"Recovery Point Objective (RPO) defines the maximum acceptable amount of data loss measured in time, indicating how far back data restoration must reach." },
  { id:10647, domain:4, level:1, question:"Which of the following is the BEST definition of a Business Continuity Plan (BCP)?", options:["A documented plan to maintain critical business functions during and after a disruption","B backup schedule for databases","C plan to replace failed hardware","D list of all organizational assets"], correct:0, explanation:"A BCP documents strategies and procedures to ensure critical business functions continue operating during and after a disruptive event." },
  { id:10648, domain:4, level:1, question:"What is the purpose of a Business Impact Analysis (BIA)?", options:["A To assess employee performance during incidents","B To identify security vulnerabilities","C To determine the financial and operational impact of a disruption to business functions","D To audit IT infrastructure"], correct:2, explanation:"A BIA identifies critical business functions, quantifies the impact of their disruption, and informs recovery priorities and objectives like RTO and RPO." },
  { id:10649, domain:4, level:1, question:"Which phase of incident response focuses on limiting the spread of an incident?", options:["A Containment","B Detection","C Preparation","D Post-Incident Review"], correct:0, explanation:"The containment phase aims to limit the damage and prevent the incident from spreading to additional systems or data." },
  { id:10650, domain:4, level:1, question:"What is the PRIMARY goal of the eradication phase in incident response?", options:["A Removing the root cause of the incident from affected systems","B Documenting lessons learned","C Restoring systems to normal operation","D Notifying stakeholders"], correct:0, explanation:"Eradication involves removing malware, closing exploited vulnerabilities, and eliminating the root cause so the incident cannot recur from the same vector." },
  { id:10651, domain:4, level:1, question:"Which of the following BEST describes a hot site?", options:["A facility with hardware but no data","B mobile recovery unit","C location with empty space and power only","D fully equipped and operational alternate facility that can assume operations immediately"], correct:3, explanation:"A hot site is a fully operational duplicate of the primary data center, allowing near-immediate failover with minimal recovery time." },
  { id:10652, domain:4, level:1, question:"A cold site differs from a hot site in that a cold site:", options:["A Has basic infrastructure but requires significant setup time before operations can resume","B Provides immediate failover capability","C Is located in the same building as the primary site","D Has fully replicated data"], correct:0, explanation:"A cold site provides basic facilities (power, space, connectivity) but lacks pre-installed hardware and data, requiring significant setup time before operations resume." },
  { id:10653, domain:4, level:1, question:"What is the purpose of an incident classification scheme?", options:["A To track the cost of incidents","B To determine who caused the incident","C To prioritize response resources and escalation based on severity","D To satisfy legal requirements"], correct:2, explanation:"Incident classification allows organizations to triage events, allocate appropriate resources, and trigger escalation procedures based on defined severity levels." },
  { id:10654, domain:4, level:1, question:"Which document outlines how an organization will communicate during a crisis?", options:["A Disaster Recovery Plan","B Crisis Communication Plan","C Business Continuity Plan","D Incident Response Playbook"], correct:1, explanation:"A crisis communication plan defines messaging strategies, spokespersons, and communication channels to maintain stakeholder confidence during a major incident." },
  { id:10655, domain:4, level:1, question:"What is chain of custody in the context of digital forensics?", options:["A The order in which systems are recovered","B documented record tracking who handled evidence, when, and how","C The sequence of incident escalation","D The order of backup restoration"], correct:1, explanation:"Chain of custody is a documented trail that records every person who handled digital evidence, ensuring its integrity and admissibility in legal proceedings." },
  { id:10656, domain:4, level:1, question:"Which of the following is a key component of forensic readiness?", options:["A Increasing backup frequency","B Hiring more security analysts","C Deploying more firewalls","D Ensuring systems are configured to collect and preserve evidence before an incident occurs"], correct:3, explanation:"Forensic readiness means proactively configuring systems to capture logs and artifacts so that evidence is available and preserved when an investigation is needed." },
  { id:10657, domain:4, level:1, question:"What is the PRIMARY purpose of a post-incident review (also called a lessons-learned meeting)?", options:["A To identify improvements to prevent recurrence and enhance response capabilities","B To satisfy legal obligations","C To calculate the financial cost of the incident","D To assign blame to responsible individuals"], correct:0, explanation:"Post-incident reviews capture lessons learned, identify root causes, and produce actionable improvements to policies, controls, and procedures." },
  { id:10658, domain:4, level:1, question:"Which of the following BEST defines Mean Time to Detect (MTTD)?", options:["A The time to fully recover from an incident","B The time to notify regulators after an incident","C The average time between the start of an incident and its detection","D The average time to contain an incident"], correct:2, explanation:"MTTD measures the average time elapsed between when an incident begins and when it is detected, serving as a key metric for detection capability." },
  { id:10659, domain:4, level:1, question:"What is a Security Information and Event Management (SIEM) system primarily used for in incident management?", options:["A Aggregating and correlating log data to detect and alert on security events","B Managing user access","C Encrypting sensitive data","D Deploying security patches"], correct:0, explanation:"A SIEM collects logs from multiple sources, correlates events, and generates alerts, enabling faster detection and analysis of security incidents." },
  { id:10660, domain:4, level:1, question:"Which of the following is the BEST description of an incident response playbook?", options:["A step-by-step procedural guide for responding to a specific type of incident","B disaster recovery schedule","C An audit checklist","D general security policy document"], correct:0, explanation:"A playbook provides detailed, actionable steps tailored to a specific incident type (e.g., ransomware, phishing), reducing decision fatigue during high-stress responses." },
  { id:10661, domain:4, level:1, question:"What is the role of a public relations team during a security incident?", options:["A Coordinating with law enforcement","B Restoring affected systems","C Managing external communications to protect the organization's reputation","D Conducting technical forensic analysis"], correct:2, explanation:"The public relations team manages external messaging to media, customers, and the public, maintaining trust and controlling the narrative during an incident." },
  { id:10662, domain:4, level:1, question:"Which of the following recovery strategies has the LOWEST cost but LONGEST recovery time?", options:["A Cold site","B Reciprocal agreement","C Hot site","D Warm site"], correct:0, explanation:"Cold sites have the lowest cost because they provide only basic infrastructure, but they require the most time to set up and become operational after a disaster." },
  { id:10663, domain:4, level:1, question:"What does the term 'dwell time' refer to in incident response?", options:["A The length of time an attacker is present in a network before detection","B The time to restore data from backup","C The duration of a tabletop exercise","D The time it takes to patch a vulnerability"], correct:0, explanation:"Dwell time measures how long a threat actor has been active in the environment before being detected, and shorter dwell time generally means less damage." },
  { id:10664, domain:4, level:1, question:"Which of the following is an example of an incident indicator of compromise (IoC)?", options:["A routine software update","B planned firewall rule change","C An unusual outbound connection to a known malicious IP address","D scheduled system restart"], correct:2, explanation:"Indicators of compromise are forensic artifacts such as suspicious network connections, unusual file hashes, or anomalous account behavior that suggest a breach." },
  { id:10665, domain:4, level:1, question:"What is the PRIMARY reason organizations conduct tabletop exercises?", options:["A To train new employees on daily tasks","B To fulfill insurance requirements","C To validate incident response procedures and identify gaps without disrupting production systems","D To test backup restoration speed"], correct:2, explanation:"Tabletop exercises walk participants through simulated incident scenarios in a discussion-based format, revealing gaps in plans and procedures with minimal operational disruption." },
  { id:10666, domain:4, level:2, question:"An organization discovers that an attacker has been exfiltrating data for three weeks before detection. Which metric BEST reflects this failure?", options:["A Recovery Point Objective (RPO)","B Mean Time to Detect (MTTD)","C Mean Time to Respond (MTTR)","D Mean Time Between Failures (MTBF)"], correct:1, explanation:"MTTD measures how long an incident goes undetected; a three-week dwell time indicates a high MTTD, reflecting poor detection capability." },
  { id:10667, domain:4, level:2, question:"During incident containment, an information security manager must choose between shutting down a compromised server and monitoring attacker activity. Which factor should MOST influence this decision?", options:["A The age of the server hardware","B The potential for ongoing data loss versus the intelligence value of observation","C The preference of the system administrator","D Whether the server has been patched recently"], correct:1, explanation:"The decision must weigh continued exposure and data loss risk against the intelligence gathered by monitoring attacker behavior, requiring risk-based judgment." },
  { id:10668, domain:4, level:2, question:"Which of the following BEST describes the difference between a disaster recovery plan (DRP) and a business continuity plan (BCP)?", options:["A DRP is tested annually; a BCP is tested monthly","B DRP is owned by IT; a BCP is owned by Legal","C DRP focuses on restoring IT systems after a disaster; a BCP addresses maintaining all critical business operations during a disruption","D DRP covers all business functions; a BCP covers only IT"], correct:2, explanation:"A DRP is IT-centric and focuses on restoring technology infrastructure, while a BCP has a broader scope covering all critical business processes needed to survive a disruption." },
  { id:10669, domain:4, level:2, question:"An organization's RTO is four hours but the last tested recovery took six hours. What should the information security manager do FIRST?", options:["A Accept the gap as within normal variance","B Analyze the reasons for the gap and revise procedures or resources to meet the RTO","C Replace the recovery team","D Extend the RTO to six hours"], correct:1, explanation:"When tested recovery time exceeds the RTO, the manager must identify and address the root cause—whether process, resource, or technical—to close the gap." },
  { id:10670, domain:4, level:2, question:"Which of the following is the MOST important element of an effective incident escalation procedure?", options:["A list of all security tools","B Detailed technical remediation steps","C budget for incident response activities","D Clearly defined thresholds and contact information so the right people are notified at the right severity level"], correct:3, explanation:"Escalation procedures must define severity thresholds and provide current contact details so appropriate decision-makers are engaged quickly without ambiguity." },
  { id:10671, domain:4, level:2, question:"A company suffers a ransomware attack and must decide whether to pay the ransom. Who should be PRIMARILY involved in this decision?", options:["A The incident responders only","B The chief information officer alone","C Senior leadership, legal counsel, and potentially law enforcement, based on organizational risk policy","D Only the IT security team"], correct:2, explanation:"Paying ransom involves legal, financial, reputational, and ethical considerations requiring senior leadership, legal, and sometimes law enforcement input, not a unilateral IT decision." },
  { id:10672, domain:4, level:2, question:"During a post-incident review, the team discovers that a critical server lacked logging. What type of control improvement does this suggest?", options:["A Corrective control improvement","B Preventive control improvement","C Detective control improvement","D Physical control improvement"], correct:2, explanation:"Adding logging to detect future incidents is a detective control, as it improves the ability to identify and analyze security events." },
  { id:10673, domain:4, level:2, question:"Which of the following BEST explains why organizations should conduct full-scale incident response exercises rather than only tabletop exercises?", options:["A Full-scale exercises test actual technical capabilities, communications, and coordination under realistic conditions","B Tabletop exercises are not useful","C Full-scale exercises satisfy all regulatory requirements","D Full-scale exercises are less expensive"], correct:0, explanation:"Full-scale exercises reveal gaps in technical execution, team coordination, and communication that discussion-based tabletop exercises cannot expose." },
  { id:10674, domain:4, level:2, question:"An incident response team collects volatile data from a compromised system. What is the CORRECT order of evidence collection based on volatility?", options:["A Logs, then disk, then memory","B CPU registers and cache, then RAM, then network state, then disk","C Disk, then logs, then memory","D Hard disk, then memory, then network connections"], correct:1, explanation:"Evidence should be collected in order of volatility—most volatile first (registers/cache, RAM, network state) to least volatile (disk)—to preserve the most transient data." },
  { id:10675, domain:4, level:2, question:"Which of the following statements BEST describes the relationship between incident response and business continuity?", options:["A Incident response supersedes BCP during cyber incidents","B They are separate programs with no interdependency","C BCP replaces incident response for large-scale events","D Incident response focuses on security events while BCP ensures critical operations continue; both must be coordinated during major incidents"], correct:3, explanation:"Incident response and BCP are complementary; during a major incident, IR handles the security response while BCP ensures the business continues to operate, and both must be coordinated." },
  { id:10676, domain:4, level:2, question:"A CISO wants to reduce the impact of future phishing-based incidents. Which proactive measure would MOST directly support this goal?", options:["A Adding more servers to the SIEM","B Deploying additional network monitoring sensors","C Increasing patch management frequency","D Implementing email filtering, user awareness training, and anti-phishing simulations"], correct:3, explanation:"Phishing incidents are best mitigated through a combination of technical controls (email filtering) and human controls (training and simulations) that address both the delivery vector and user behavior." },
  { id:10677, domain:4, level:2, question:"Which of the following is the MOST critical output of a Business Impact Analysis?", options:["A complete risk register","B An asset valuation report","C Identification of critical functions with their associated RTO, RPO, and minimum resource requirements","D list of all IT assets"], correct:2, explanation:"The BIA's most critical output is the prioritized list of critical business functions with their recovery objectives and minimum resource requirements, which directly drives BCP and DRP design." },
  { id:10678, domain:4, level:2, question:"An organization experiences a data breach and is required to notify affected individuals. What should govern the notification timeline?", options:["A Applicable legal and regulatory requirements defining mandatory notification windows","B The preference of the marketing department","C The organization's public relations strategy","D The speed of the forensic investigation"], correct:0, explanation:"Breach notification timelines are dictated by applicable laws and regulations (e.g., GDPR's 72-hour rule, state breach notification laws), not organizational convenience." },
  { id:10679, domain:4, level:2, question:"What is the PRIMARY purpose of maintaining an incident log during a response?", options:["A To satisfy auditors","B To communicate with the public","C To create a chronological record of actions taken, decisions made, and evidence gathered for accountability and post-incident analysis","D To track costs for insurance claims only"], correct:2, explanation:"An incident log provides a time-stamped record that supports accountability, enables post-incident review, and may serve as evidence in legal or regulatory proceedings." },
  { id:10680, domain:4, level:2, question:"Which recovery strategy involves a mutual agreement between two organizations to provide each other with backup facilities in the event of a disaster?", options:["A Cold site","B Reciprocal agreement","C Warm site","D Hot site"], correct:1, explanation:"A reciprocal agreement is a low-cost strategy where two organizations agree to provide backup space and resources to each other, though it introduces risks around capacity and confidentiality." },
  { id:10681, domain:4, level:2, question:"A security analyst detects unusual lateral movement across the network. Which incident response phase should be initiated IMMEDIATELY?", options:["A Containment","B Preparation","C Eradication","D Post-incident review"], correct:0, explanation:"Upon detection of active lateral movement, containment must be initiated immediately to limit the attacker's ability to access additional systems and data." },
  { id:10682, domain:4, level:2, question:"What is the key difference between Mean Time to Respond (MTTR) and Mean Time to Recover?", options:["A They are the same metric with different names","B Mean Time to Recover applies only to hardware failures","C Mean Time to Respond measures time to begin a response; Mean Time to Recover measures time to fully restore normal operations","D Mean Time to Respond is only used in network operations"], correct:2, explanation:"MTTR (respond) captures how quickly the team engages after detection, while Mean Time to Recover measures how long it takes to fully restore the affected service to normal operation." },
  { id:10683, domain:4, level:2, question:"During an incident, the security team wants to preserve evidence on a live system before shutdown. Which action should be taken FIRST?", options:["A Reimage the system","B Power off the system immediately","C Capture a memory dump to preserve volatile data","D Disconnect the system from the network"], correct:2, explanation:"Memory contains volatile artifacts such as running processes, encryption keys, and network connections that are lost on shutdown, so capturing a memory dump is the priority before any shutdown action." },
  { id:10684, domain:4, level:2, question:"Which of the following scenarios BEST illustrates the need for cyber insurance?", options:["A An organization installs a new firewall","B An organization wants to transfer residual financial risk from cyber incidents such as breach notification costs and ransomware payments","C An organization conducts a vulnerability scan","D An organization updates its access control policy"], correct:1, explanation:"Cyber insurance is a risk transfer mechanism that covers residual financial exposures from cyber incidents—including notification costs, legal fees, and ransom payments—that cannot be fully mitigated." },
  { id:10685, domain:4, level:2, question:"What should an organization do FIRST when a critical system is suspected of being compromised?", options:["A Notify all employees","B Determine the scope of compromise before taking action to avoid destroying evidence","C Immediately restore from backup","D Reformat the affected system"], correct:1, explanation:"Before taking remediation actions, the team must scope the compromise to understand affected systems, preserve evidence, and avoid inadvertently destroying forensic artifacts." },
  { id:10686, domain:4, level:2, question:"Which element of crisis communication is MOST important to establish before an incident occurs?", options:["A social media monitoring subscription","B Designated spokespersons and pre-approved communication templates","C Draft press releases for every possible scenario","D list of all journalists' contact information"], correct:1, explanation:"Pre-designating spokespersons and preparing communication templates ensures that accurate, consistent messages can be delivered quickly without creating confusion during a crisis." },
  { id:10687, domain:4, level:2, question:"An organization's BCP has not been tested in two years. What is the GREATEST risk associated with this?", options:["A The plan will be too expensive to execute","B Employees will memorize the plan incorrectly","C The plan will become too detailed","D The plan may not reflect current systems, personnel, or threats, rendering it ineffective during a real disaster"], correct:3, explanation:"Untested plans become stale as systems, staff, and threats evolve; without testing, the organization cannot be confident the plan will work when needed." },
  { id:10688, domain:4, level:2, question:"Which of the following BEST describes the purpose of network segmentation during an incident?", options:["A To isolate compromised segments to prevent lateral movement and limit the spread of the incident","B To simplify network management","C To reduce software licensing costs","D To improve network performance"], correct:0, explanation:"Network segmentation allows responders to isolate compromised zones, limiting the attacker's ability to move laterally to other systems or data stores." },
  { id:10689, domain:4, level:2, question:"What is the PRIMARY benefit of integrating threat intelligence into incident response?", options:["A Replacing the need for a SIEM","B Providing context about attacker tactics, techniques, and procedures (TTPs) to accelerate detection and response","C Eliminating the need for forensic analysis","D Reducing the number of security analysts needed"], correct:1, explanation:"Threat intelligence provides actionable context about known adversary TTPs and IoCs, enabling faster detection, more informed containment decisions, and better attribution." },
  { id:10690, domain:4, level:2, question:"An organization needs to maintain operations during a prolonged power outage. Which control BEST supports this requirement?", options:["A Adding more security cameras","B Implementing uninterruptible power supplies (UPS) and backup generators","C Increasing bandwidth","D Deploying additional antivirus software"], correct:1, explanation:"UPS and backup generators provide power continuity during outages, directly supporting the availability component of the CIA triad and business continuity objectives." },
  { id:10691, domain:4, level:2, question:"Which of the following is the BEST indicator that an incident response program is maturing?", options:["A More expensive tools are deployed","B The number of incidents detected increases every year","C The incident response team grows in size","D Metrics show decreasing MTTD and MTTR, and lessons learned are consistently incorporated into improved procedures"], correct:3, explanation:"Program maturity is demonstrated by measurable improvements in detection and response times, combined with a continuous improvement cycle driven by lessons learned." },
  { id:10692, domain:4, level:2, question:"A forensic investigator must analyze a hard drive without altering its contents. Which tool should be used?", options:["A standard file manager","B disk defragmenter","C backup utility","D write blocker to create a forensic image before analysis"], correct:3, explanation:"A write blocker prevents any writes to the original evidence drive during imaging, ensuring that the original evidence remains unaltered and forensically sound." },
  { id:10693, domain:4, level:2, question:"Which of the following MOST accurately describes a warm site?", options:["A mobile recovery trailer","B fully operational duplicate of the primary site","C An empty building with power only","D facility with hardware and connectivity that requires some configuration and data restoration before use"], correct:3, explanation:"A warm site has pre-installed hardware and connectivity but requires configuration and data restoration, offering a balance between the cost of a cold site and the readiness of a hot site." },
  { id:10694, domain:4, level:2, question:"What is the MAIN purpose of defining minimum acceptable service levels in a BCP?", options:["A To limit employee overtime","B To reduce IT costs","C To establish the lowest level of service at which the business can operate and still meet critical obligations during a disruption","D To satisfy vendor contracts"], correct:2, explanation:"Minimum service levels define the floor of acceptable operations, ensuring the BCP focuses resources on sustaining the functions most essential to organizational survival." },
  { id:10695, domain:4, level:2, question:"Which of the following actions BEST supports evidence integrity during a security incident investigation?", options:["A Creating cryptographic hashes of evidence before and after collection to verify integrity","B Sharing evidence files via email","C Allowing all team members access to original evidence","D Using the production system to search for malware"], correct:0, explanation:"Cryptographic hashing (e.g., MD5, SHA-256) of evidence before and after handling provides a verifiable proof that the evidence has not been altered, supporting admissibility." },
  { id:10696, domain:4, level:2, question:"An organization wants to reduce the financial impact of a major cyber incident. Which strategy is MOST effective when combined with strong security controls?", options:["A Hiring more security staff","B Deploying more endpoint agents","C Increasing the security budget","D Cyber insurance to transfer residual financial risk"], correct:3, explanation:"After implementing strong controls to reduce incident likelihood and impact, cyber insurance transfers the residual financial risk that controls cannot fully eliminate." },
  { id:10697, domain:4, level:2, question:"Which of the following is MOST important when communicating with law enforcement during a security incident?", options:["A Posting incident details publicly before contacting law enforcement","B Sharing all system access credentials","C Waiting until the incident is fully resolved","D Providing factual, documented information while consulting legal counsel about what can be disclosed"], correct:3, explanation:"Law enforcement engagement must be managed carefully—sharing factual, documented information through proper channels with legal guidance protects the organization's legal standing and investigation integrity." },
  { id:10698, domain:4, level:2, question:"A company's incident response team is overwhelmed during a large-scale incident. What should the incident commander do FIRST?", options:["A Wait for the incident to resolve itself","B Shut down all systems","C Activate mutual aid agreements or engage a third-party incident response retainer","D Dismiss the team and start fresh"], correct:2, explanation:"When internal capacity is exceeded, activating pre-arranged mutual aid agreements or third-party IR retainers provides additional skilled resources quickly." },
  { id:10699, domain:4, level:2, question:"Which of the following BEST describes the purpose of an incident response retainer?", options:["A pre-negotiated agreement with a third-party IR firm to provide rapid response support when needed","B software license for IR tools","C An insurance policy","D contract for regular security audits"], correct:0, explanation:"An IR retainer is a pre-negotiated agreement ensuring rapid access to external incident response expertise and resources without the delay of procurement during an active crisis." },
  { id:10700, domain:4, level:2, question:"What is the MOST important factor in determining the severity classification of a security incident?", options:["A The actual or potential impact on organizational assets, operations, and stakeholders","B Whether the attacker has been identified","C The time of day the incident occurred","D The technical sophistication of the attack"], correct:0, explanation:"Severity classification should be driven by the business impact—financial, operational, reputational, and legal consequences—rather than purely technical attributes." },
  { id:10701, domain:4, level:3, question:"An organization is designing an incident response program and wants to align it with an established framework. Which framework is MOST specifically focused on incident response?", options:["A COBIT 2019","B NIST SP 800-61 (Computer Security Incident Handling Guide)","C The Balanced Scorecard","D ISO/IEC 27001"], correct:1, explanation:"NIST SP 800-61 is the authoritative guide specifically dedicated to computer security incident handling, providing a lifecycle model and practical guidance for IR programs." },
  { id:10702, domain:4, level:3, question:"An information security manager discovers that the organization's incident response plan does not address supply chain compromises. Which step should be taken FIRST?", options:["A Remove supply chain vendors","B Conduct a gap analysis to assess the risk and update the plan with supply chain-specific scenarios and procedures","C Wait for a supply chain incident to occur before updating the plan","D Purchase new security software"], correct:1, explanation:"Identifying the gap through a risk-focused analysis is the first step; the plan should then be updated with specific procedures addressing supply chain threat vectors." },
  { id:10703, domain:4, level:3, question:"A forensic analysis reveals that an attacker used living-off-the-land (LotL) techniques, using only native OS tools. How does this MOST impact the investigation?", options:["A It complicates detection because malicious activity blends with legitimate administrative actions","B It has no impact on the investigation","C It makes detection easier because native tools leave more logs","D It eliminates the need for memory forensics"], correct:0, explanation:"LotL techniques abuse legitimate system tools, making malicious actions difficult to distinguish from normal administration and requiring sophisticated behavioral analysis." },
  { id:10704, domain:4, level:3, question:"During a major incident, the security team identifies multiple attack vectors used simultaneously. This MOST likely indicates:", options:["A An opportunistic attack by a single unskilled attacker","B routine network scan","C system misconfiguration","D coordinated, advanced persistent threat (APT) campaign requiring a comprehensive, coordinated response"], correct:3, explanation:"Simultaneous use of multiple attack vectors suggests a sophisticated, organized threat actor (APT) with planning and resources, requiring coordinated IR beyond a simple single-vector response." },
  { id:10705, domain:4, level:3, question:"An organization's incident response team is considering deploying deception technology (honeypots). What is the GREATEST benefit in an IR context?", options:["A Honeypots replace the need for a SIEM","B Honeypots are primarily a compliance tool","C Honeypots attract and detect attackers early, providing intelligence on TTPs with minimal false positives","D Honeypots prevent all attacks"], correct:2, explanation:"Honeypots have no legitimate production activity, so any interaction is inherently suspicious, providing high-fidelity early detection and rich intelligence on attacker behavior." },
  { id:10706, domain:4, level:3, question:"A CISM candidate is reviewing the organization's cyber insurance policy before a major incident occurs. Which policy element is MOST critical to verify?", options:["A Coverage inclusions and exclusions, especially for first-party costs, regulatory fines, and ransomware payments","B The policy renewal date","C The name of the insurer","D The premium payment schedule"], correct:0, explanation:"Understanding exactly what is and is not covered—particularly for high-cost elements like ransomware, regulatory fines, and notification costs—is essential before relying on the policy during an incident." },
  { id:10707, domain:4, level:3, question:"An organization with a 4-hour RTO for its core payment system has just suffered a ransomware attack. Recovery testing showed 8 hours is needed. What is the MOST appropriate immediate action?", options:["A Extend the RTO to 8 hours permanently","B Pay the ransom immediately","C Shut down the payment system indefinitely","D Activate alternative manual processing procedures while accelerating the technical recovery effort"], correct:3, explanation:"When RTO cannot be met through technical recovery alone, interim manual or alternative procedures must be activated to maintain business continuity while the technical recovery proceeds." },
  { id:10708, domain:4, level:3, question:"Which of the following BEST describes 'purple team' exercises in the context of incident response improvement?", options:["A Exercises conducted by external auditors","B Collaborative exercises where red team (attackers) and blue team (defenders) work together to improve detection and response in real time","C Exercises focused only on physical security","D Exercises where only defenders participate"], correct:1, explanation:"Purple teaming combines offensive (red) and defensive (blue) capabilities in a collaborative format to directly improve detection logic, response playbooks, and analyst skills simultaneously." },
  { id:10709, domain:4, level:3, question:"An incident manager is deciding whether to engage law enforcement following a cyberattack. Which consideration should carry the MOST weight?", options:["A The legal obligations, potential impact on the investigation, and organizational risk tolerance, all assessed with legal counsel","B The size of the attacking botnet","C Whether the incident was disclosed publicly","D The personal preference of the CISO"], correct:0, explanation:"Law enforcement engagement is a multi-dimensional decision involving legal obligations (mandatory reporting in some sectors), investigative impact, and organizational risk appetite, requiring legal counsel input." },
  { id:10710, domain:4, level:3, question:"A security team detects a zero-day exploit being used against a critical application. No patch is available. What is the MOST appropriate immediate containment action?", options:["A Wait for the vendor to release a patch","B Shut down the entire organization's network","C Ignore the threat until a patch is available","D Isolate the affected application, implement compensating controls such as WAF rules or network restrictions, and notify the vendor"], correct:3, explanation:"Without a patch, the response must focus on isolation, compensating controls (WAF rules, additional monitoring, network restrictions), and vendor coordination to minimize exposure." },
  { id:10711, domain:4, level:3, question:"An organization's incident response metrics show a high volume of low-severity alerts but poor detection of high-severity incidents. This MOST likely indicates:", options:["A The organization has no real threats","B The SIEM is working correctly","C The organization needs more analysts","D Alert fatigue may be desensitizing analysts, or detection rules are poorly tuned to prioritize high-severity threats"], correct:3, explanation:"A high volume of low-severity (often false positive) alerts creates alert fatigue, causing analysts to miss critical events; this signals the need for detection rule tuning and alert prioritization." },
  { id:10712, domain:4, level:3, question:"Which of the following represents the MOST advanced maturity level for an organization's incident response capability?", options:["A Ad hoc response with no documented procedures","B dedicated IR team with standard playbooks","C Continuous improvement driven by threat intelligence integration, automation, and measurable performance metrics","D Documented procedures that are tested annually"], correct:2, explanation:"The highest maturity level integrates threat intelligence, automation (SOAR), and continuous measurement into a self-improving program, far exceeding the baseline of documented procedures or a dedicated team." },
  { id:10713, domain:4, level:3, question:"During a major ransomware incident, the IR team discovers that backups are also encrypted. This MOST significantly impacts which recovery metric?", options:["A The number of affected endpoints","B RPO, as the organization may have to accept significant data loss beyond the last clean backup","C MTTD","D MTTR for the initial detection"], correct:1, explanation:"Encrypted backups mean recovery must fall back to the last unaffected backup, potentially extending the data loss window well beyond the planned RPO." },
  { id:10714, domain:4, level:3, question:"An information security manager wants to improve the organization's ability to attribute a cyberattack to a specific threat actor. Which capability is MOST valuable for this purpose?", options:["A Enhanced data loss prevention (DLP)","B Threat intelligence combined with advanced forensic analysis of malware samples and infrastructure","C Increased patch management frequency","D Stronger access controls"], correct:1, explanation:"Attribution requires correlating technical indicators (malware code, C2 infrastructure, TTPs) with threat intelligence databases, making threat intel and forensic analysis central to attribution efforts." },
  { id:10715, domain:4, level:3, question:"A company operates across multiple jurisdictions with different breach notification requirements. What is the BEST approach to managing this complexity?", options:["A Notify only the jurisdiction where the company is headquartered","B Develop a notification decision tree that maps incident characteristics to the most stringent applicable jurisdictional requirements","C Apply the most lenient notification requirement globally","D Delegate notification decisions entirely to each country's local IT team"], correct:1, explanation:"A decision tree approach ensures compliance with all applicable laws by mapping incident attributes to each jurisdiction's requirements, applying the most stringent where they overlap." },
  { id:10716, domain:4, level:3, question:"An organization experiences a DDoS attack that exhausts its internet bandwidth. Which FIRST-step mitigation is MOST effective?", options:["A Upgrading the internet connection speed","B Rebooting all internet-facing servers","C Deploying a new firewall","D Activating upstream scrubbing services or contacting the ISP to filter malicious traffic"], correct:3, explanation:"Upstream scrubbing centers or ISP-level black-hole routing address the attack at the network level before traffic reaches the organization, which is more effective than local device-level responses." },
  { id:10717, domain:4, level:3, question:"What distinguishes an advanced persistent threat (APT) actor from a typical cybercriminal in terms of incident response challenges?", options:["A APT actors only target large companies","B APT actors always use ransomware","C APT actors have long-term objectives, extensive resources, and sophisticated tradecraft, requiring more thorough and sustained IR efforts to fully eradicate","D APT attacks are always louder and easier to detect"], correct:2, explanation:"APT actors maintain persistent, stealthy access over months or years and may establish multiple footholds, requiring comprehensive and sustained IR to fully eliminate the threat." },
  { id:10718, domain:4, level:3, question:"An organization wants to ensure its incident response program addresses insider threats. Which control is MOST important to include?", options:["A Only external threat monitoring","B Blocking all employee internet access","C User and Entity Behavior Analytics (UEBA) to detect anomalous insider activity alongside clear investigation procedures for insider threat cases","D Restricting all remote access"], correct:2, explanation:"UEBA baselines normal behavior and detects deviations indicative of insider threats; combined with formal investigation procedures, it provides both detection and a structured response capability." },
  { id:10719, domain:4, level:3, question:"During a crisis, the CEO asks the CISO for an immediate update. Which type of communication is MOST appropriate at this stage?", options:["A list of all firewall logs","B concise executive briefing covering confirmed facts, business impact, current actions, and next steps","C press release","D detailed 50-page technical forensics report"], correct:1, explanation:"Executives need actionable, impact-focused information in a concise format; a structured briefing covering what is known, business impact, and response status enables sound decision-making." },
  { id:10720, domain:4, level:3, question:"What is the PRIMARY purpose of a Security Orchestration, Automation, and Response (SOAR) platform in incident response?", options:["A To manage vulnerability scanning","B To replace the incident response team","C To automate repetitive response tasks, orchestrate workflows across tools, and accelerate incident handling at scale","D To store forensic evidence"], correct:2, explanation:"SOAR platforms automate high-volume, repetitive tasks (e.g., IOC lookups, ticket creation) and orchestrate multi-tool workflows, allowing analysts to focus on complex decisions and reducing MTTR." },
  { id:10721, domain:4, level:1, question:"What is the purpose of an incident response retainer agreement?", options:["A To satisfy PCI DSS requirements","B To guarantee that no incidents will occur","C To ensure pre-negotiated access to external IR expertise and resources during an incident","D To replace internal incident response capabilities"], correct:2, explanation:"An IR retainer pre-establishes the commercial and legal terms with a specialist firm, enabling rapid engagement without procurement delays during an active incident." },
  { id:10722, domain:4, level:1, question:"Which of the following BEST defines 'eradication' in the context of incident response?", options:["A Notifying affected customers","B Removing malicious components, closing vulnerabilities, and eliminating the attacker's foothold from all affected systems","C Restoring systems to normal operation","D Conducting a post-incident review"], correct:1, explanation:"Eradication is the phase where all malicious artifacts are removed and the attack vector is closed, ensuring the threat cannot re-emerge from the same entry point." },
  { id:10723, domain:4, level:1, question:"Which metric measures how quickly an organization can restore normal operations after an incident?", options:["A RTO","B RPO","C MTTR (Mean Time to Recover)","D MTTD"], correct:2, explanation:"Mean Time to Recover (MTTR) measures the average time from incident detection to full restoration of normal operations, indicating recovery efficiency." },
  { id:10724, domain:4, level:1, question:"What is the PRIMARY goal of the recovery phase in incident response?", options:["A Identifying the attacker","B Restoring affected systems and services to normal operation securely","C Collecting forensic evidence","D Communicating with the press"], correct:1, explanation:"The recovery phase focuses on bringing systems back online in a secure state, verifying they are clean, and returning the organization to normal operations." },
  { id:10725, domain:4, level:1, question:"Which of the following is an example of a preventive control in incident management?", options:["A Security awareness training that prevents users from clicking phishing links","B Post-incident review","C Intrusion detection system","D Log management"], correct:0, explanation:"Preventive controls reduce the likelihood of an incident occurring; security awareness training reduces successful phishing attacks before they happen." },
  { id:10726, domain:4, level:1, question:"What does 'scope' mean in the context of incident containment?", options:["A The financial cost of the incident","B Understanding which systems, data, and networks are affected by the incident","C The regulatory body notified","D The name of the attacker"], correct:1, explanation:"Scoping the incident means identifying all affected systems, accounts, and data to ensure containment actions are comprehensive and no affected areas are overlooked." },
  { id:10727, domain:4, level:1, question:"Which of the following is the BEST description of an incident response team structure?", options:["A defined team with specific roles (incident commander, communications lead, technical analyst, legal) who coordinate the response","B Any available employee","C single person responsible for all incidents","D Only external consultants"], correct:0, explanation:"Effective IR teams have clearly defined roles and responsibilities, ensuring coordinated action without confusion about who is responsible for each aspect of the response." },
  { id:10728, domain:4, level:1, question:"Why is it important to notify legal counsel early in a significant security incident?", options:["A Legal counsel manages the IT infrastructure","B Legal counsel provides guidance on obligations, liability, evidence handling, and attorney-client privilege considerations","C Legal counsel communicates with the media","D Legal counsel can fix the technical issue"], correct:1, explanation:"Early legal involvement ensures the organization understands its notification obligations, manages liability exposure, and may invoke attorney-client privilege over sensitive communications." },
  { id:10729, domain:4, level:1, question:"What does 'mean time between failures' (MTBF) measure?", options:["A The average cost of an incident","B The time to detect an incident","C The time to recover from an incident","D The average time a system operates between failures, used to plan maintenance and redundancy"], correct:3, explanation:"MTBF is a reliability metric that measures average operating time between failures, informing decisions about redundancy, maintenance schedules, and availability planning." },
  { id:10730, domain:4, level:1, question:"Which of the following BEST describes 'forensic readiness'?", options:["A Proactively configuring systems and processes to maximize the ability to collect, preserve, and use digital evidence when needed","B Training forensic analysts","C Purchasing forensic software licenses","D Having forensic tools available on the shelf"], correct:0, explanation:"Forensic readiness is a proactive state where systems are configured to capture relevant evidence and procedures are in place to handle it correctly before an incident occurs." },
  { id:10731, domain:4, level:2, question:"An organization's incident response plan requires the CISO to approve all external disclosures. During an incident, the CISO is unreachable. What should the plan include to address this?", options:["A Halt all disclosures until the CISO is available","B Allow any employee to make disclosures","C defined delegation of authority specifying who can authorize disclosures in the CISO's absence","D Ignore disclosure requirements temporarily"], correct:2, explanation:"Incident response plans must include delegation of authority provisions to ensure critical decisions like external disclosures can be made in a timely manner without depending on a single individual." },
  { id:10732, domain:4, level:2, question:"A company discovers that a third-party vendor's compromised credentials were used to access its systems. What should the incident response team do FIRST?", options:["A Notify the press","B Revoke or reset the vendor's access credentials and investigate the full scope of access","C Ignore the issue since it originated with the vendor","D Terminate the vendor contract immediately"], correct:1, explanation:"Immediately revoking compromised credentials stops ongoing unauthorized access, while simultaneously scoping what was accessed enables a comprehensive response." },
  { id:10733, domain:4, level:2, question:"Which of the following BEST describes 'indicators of attack' (IoAs) versus 'indicators of compromise' (IoCs)?", options:["A IoAs are only used in physical security","B IoCs are more useful than IoAs in all cases","C IoAs and IoCs are identical","D IoCs are artifacts of past compromise; IoAs identify active attack behaviors in progress, enabling earlier detection"], correct:3, explanation:"IoCs (file hashes, malicious IPs) indicate a breach has occurred; IoAs (command execution patterns, privilege escalation behavior) identify ongoing attack activity, enabling earlier intervention." },
  { id:10734, domain:4, level:2, question:"An organization suffers a major IT outage due to a natural disaster. The BCP is activated. Which function should be restored FIRST?", options:["The employee cafeteria","B The functions identified as highest priority in the Business Impact Analysis","C The organization's website","D Non-critical administrative functions"], correct:1, explanation:"The BIA establishes recovery priorities based on criticality and impact; BCP activation should restore the highest-priority, most business-critical functions first." },
  { id:10735, domain:4, level:2, question:"What is the MOST important reason to keep incident response playbooks up to date?", options:["A Because playbooks must be updated monthly regardless of changes","B To impress auditors","C To reduce the size of the IT budget","D Because outdated playbooks may not address current threats, tools, or organizational changes, leading to ineffective responses"], correct:3, explanation:"Playbooks that don't reflect current systems, threats, or personnel become useless or misleading during an actual incident; regular updates ensure they remain accurate and actionable." },
  { id:10736, domain:4, level:2, question:"Which of the following is a KEY challenge in cloud-based incident response compared to on-premises?", options:["A Cloud providers always handle all incident response","B Cloud environments are immune to incidents","C Limited physical access and shared responsibility for controls between the organization and the cloud provider","D Cloud environments have no logs"], correct:2, explanation:"In cloud environments, the shared responsibility model limits direct access to some infrastructure, and the organization may depend on the provider for certain logs and forensic capabilities." },
  { id:10737, domain:4, level:2, question:"An organization wants to test whether its backup restoration process meets its RPO. Which type of test is MOST appropriate?", options:["A functional test that actually restores data from backup and verifies integrity and completeness","B vulnerability scan","C Tabletop exercise","D policy review"], correct:0, explanation:"Only an actual restoration test can verify that backup data is complete, uncorrupted, and restoreable within the RPO; discussion-based tests cannot validate technical recovery capability." },
  { id:10738, domain:4, level:2, question:"Which of the following BEST describes the concept of 'incident triage'?", options:["A Assigning all incidents to the same analyst","B Deleting low-severity incidents","C Quickly assessing incoming events to determine their validity, severity, and priority for response allocation","D Fixing all incidents at once"], correct:2, explanation:"Triage rapidly evaluates events to distinguish true incidents from false alarms and prioritizes them by severity, ensuring critical incidents receive prompt attention." },
  { id:10739, domain:4, level:2, question:"An organization discovers that a former employee's account was used to exfiltrate data after termination. Which process failure MOST directly caused this?", options:["A Failure of the access de-provisioning process to revoke account access upon termination","B Weak password policy","C Lack of a SIEM","D Insufficient monitoring"], correct:0, explanation:"The root cause is a failure in the offboarding/de-provisioning process; the account should have been disabled immediately upon termination, before any potential misuse." },
  { id:10740, domain:4, level:2, question:"Which of the following is the MOST effective way to measure the effectiveness of an incident response program?", options:["A Measuring the number of security policies","B Counting the number of security certifications held by staff","C Tracking key metrics such as MTTD, MTTR, incident recurrence rate, and percentage of playbooks tested","D Counting the number of firewalls deployed"], correct:2, explanation:"Quantitative metrics like MTTD, MTTR, and recurrence rate directly reflect IR program effectiveness and enable trend analysis and benchmarking over time." },
  { id:10741, domain:4, level:2, question:"Why is it important to establish communication protocols with external parties (regulators, customers, media) before an incident occurs?", options:["A Because regulators require pre-incident communication plans only in financial services","B To eliminate the need for legal counsel during an incident","C Because the media must be notified before regulators","D To ensure rapid, accurate, and legally compliant communication when an incident occurs, without time pressure"], correct:3, explanation:"Pre-established protocols ensure that external communication during an incident is timely, accurate, and legally reviewed—reducing the risk of miscommunication under pressure." },
  { id:10742, domain:4, level:2, question:"What is the purpose of a 'war room' or incident command center during a major security incident?", options:["A secure room for storing forensic evidence","B room for executive meetings unrelated to the incident","C dedicated, centralized coordination hub that brings together key stakeholders to manage all aspects of the incident response","D location for media briefings"], correct:2, explanation:"A war room centralizes decision-making, communication, and coordination, ensuring all response teams have shared situational awareness and can act in concert." },
  { id:10743, domain:4, level:3, question:"An organization is evaluating its incident response program against the NIST Cybersecurity Framework. The organization has formal IR processes but does not adapt them based on threat intelligence. Which maturity tier BEST describes this state?", options:["A Tier 1 – Partial","B Tier 4 – Adaptive","C Tier 2 – Risk Informed","D Tier 3 – Repeatable"], correct:3, explanation:"Tier 3 (Repeatable) describes organizations with formalized, approved processes but lacking the adaptive, threat-intelligence-driven continuous improvement that characterizes Tier 4." },
  { id:10744, domain:4, level:3, question:"During a large-scale incident, the organization's primary communication channels (email, phone) are compromised. What should the IR plan specify for this scenario?", options:["A Use social media to coordinate all internal response activities","B Wait for IT to restore email before communicating","C Pre-established out-of-band communication channels (e.g., encrypted messaging apps, secure conference bridges) that are independent of the primary infrastructure","D Suspend all communications until systems are restored"], correct:2, explanation:"Out-of-band communication channels that are independent of the compromised infrastructure ensure the IR team can coordinate effectively even when primary systems are unavailable." },
  { id:10745, domain:4, level:3, question:"A threat actor uses a supply chain attack to compromise software used by thousands of organizations. What makes this scenario uniquely challenging for incident response?", options:["A Supply chain attacks only affect small companies","B Supply chain attacks are always minor","C The software vendor is solely responsible for response","D The attacker is present in all affected organizations before detection, discovery may require coordinated response across industries, and remediation involves third-party software"], correct:3, explanation:"Supply chain attacks create simultaneous compromise across many organizations, require coordination with the software vendor for remediation, and may involve extended dwell time before discovery." },
  { id:10746, domain:4, level:3, question:"An organization is conducting a post-mortem after a significant breach. The root cause is identified as an unpatched vulnerability that had been known for three months. Which systemic improvement should be HIGHEST priority?", options:["A Purchasing more security tools","B Increasing the size of the IR team","C Improving the vulnerability management process to reduce time to patch critical vulnerabilities","D Updating the incident response policy"], correct:2, explanation:"The systemic failure is in patch management; improving the process to ensure critical vulnerabilities are patched promptly directly addresses the root cause and prevents similar breaches." },
  { id:10747, domain:4, level:3, question:"What is the MOST significant risk of relying solely on automated SOAR playbooks for incident response without human oversight?", options:["A SOAR platforms are difficult to configure","B Automated playbooks are too slow","C SOAR platforms are too expensive","D Automated playbooks may take incorrect or disproportionate actions in unanticipated scenarios, causing more harm than the original incident"], correct:3, explanation:"Fully automated responses can execute incorrect actions in novel or ambiguous situations, potentially disrupting legitimate systems or escalating an incident; human oversight is essential for judgment-dependent decisions." },
  { id:10748, domain:4, level:3, question:"An organization's incident response team identifies a compromised system that is also processing transactions for a regulated financial product. What additional consideration MUST be factored into the containment decision?", options:["A The server's warranty status","B The physical weight of the server","C Regulatory requirements around availability and data integrity for regulated financial systems, which may limit or shape containment options","D The color of the server rack"], correct:2, explanation:"Regulated systems may have specific requirements around availability, data handling, and notification that constrain containment options and require coordination with compliance and legal teams." },
  { id:10749, domain:4, level:3, question:"Which of the following is the MOST important outcome of a well-executed post-incident review?", options:["A Identifying who is to blame for the incident","B Filing the incident report for insurance purposes","C Satisfying auditors that the incident was handled correctly","D Producing actionable improvements that are tracked and implemented to reduce the likelihood or impact of future incidents"], correct:3, explanation:"The ultimate goal of a post-incident review is continuous improvement—generating specific, tracked action items that strengthen controls, processes, and capabilities against future incidents." },
  { id:10750, domain:4, level:3, question:"An organization operates critical infrastructure subject to sector-specific incident reporting requirements. A cyber incident occurs. What is the FIRST action related to regulatory compliance?", options:["A Notify the media before regulators","B Wait for the full investigation to complete before any reporting","C Determine which regulatory reporting obligations apply, their timelines, and required notification content, then engage legal counsel","D Fix the technical issue before any notifications"], correct:2, explanation:"Regulated sectors have mandatory and time-bound reporting obligations; immediately determining applicable requirements and timelines ensures the organization does not inadvertently violate reporting rules during the response." },
  { id:10751, domain:4, level:1, question:"What is the goal of 'recovery' as a phase in the NIST incident response lifecycle?", options:["A Identifying and prosecuting the attacker","B Notifying regulators","C Collecting and preserving evidence","D Restoring affected systems to normal operation and confirming they are free of malicious artifacts"], correct:3, explanation:"The recovery phase focuses on restoring systems to a known-good state and validating that they are clean before returning them to production." },
  { id:10752, domain:4, level:1, question:"Which of the following is the BEST example of a detective control in incident management?", options:["A Intrusion detection system (IDS) generating alerts on suspicious network activity","B Firewall rules blocking malicious traffic","C Two-factor authentication","D Encryption of sensitive data"], correct:0, explanation:"Detective controls identify and alert on events after they occur; an IDS monitors and alerts on suspicious activity, exemplifying detective capability." },
  { id:10753, domain:4, level:1, question:"What does 'triage' mean in the context of security incident management?", options:["A Notifying all users about every alert","B Closing incidents without investigation","C Quickly assessing and prioritizing incidents based on severity and potential impact","D Deleting log entries"], correct:2, explanation:"Triage is the rapid assessment process that separates genuine incidents from false alarms and prioritizes them so limited response resources are directed at the most critical events first." },
  { id:10754, domain:4, level:1, question:"Which of the following BEST describes a corrective control in incident response?", options:["A system that prevents attacks","B monitoring system that detects attacks","C An access control that limits user permissions","D control that restores systems or data to their proper state after an incident, such as restoring from backup"], correct:3, explanation:"Corrective controls act after an incident to fix damage; restoring from backup is a classic corrective control that returns data to a known-good state." },
  { id:10755, domain:4, level:1, question:"Why should incident response team members be trained regularly?", options:["A To meet annual performance review requirements","B To eliminate the need for documented procedures","C To ensure skills and knowledge remain current with evolving threats, tools, and procedures","D To reduce salaries through cross-training"], correct:2, explanation:"Regular training ensures the team is proficient with current tools, aware of new threat techniques, and able to execute updated procedures effectively under stress." },
  { id:10756, domain:4, level:1, question:"Which of the following is MOST important to include in an incident notification to senior management?", options:["A The names of all systems involved","B Detailed technical forensic findings","C The full incident log","D concise summary of the incident, business impact, current response status, and immediate decisions needed"], correct:3, explanation:"Senior management needs actionable, impact-focused information to make decisions; they do not need raw technical details but must understand business impact and what decisions are required." },
  { id:10757, domain:4, level:1, question:"What is the purpose of an incident response communication tree?", options:["A To define who must be notified and in what order based on incident severity, ensuring the right people are reached quickly","B To document forensic evidence","C To track recovery progress","D To organize the network topology"], correct:0, explanation:"A communication tree ensures that appropriate stakeholders are notified in a defined order and timeframe corresponding to the incident's severity, preventing notification gaps." },
  { id:10758, domain:4, level:1, question:"Which of the following BEST describes 'lessons learned' in the context of incident response?", options:["A report filed with regulators","B list of attacker IP addresses","C An analysis of what happened, what worked, what did not, and what improvements should be made, conducted after an incident is resolved","D legal document filed after every incident"], correct:2, explanation:"Lessons learned is a structured review process that identifies both successes and failures during the response, generating improvements to prevent future incidents or improve future responses." },
  { id:10759, domain:4, level:1, question:"What is the PRIMARY benefit of having a pre-approved budget for incident response activities?", options:["A It guarantees no incidents will occur","B It reduces the number of incidents","C It eliminates the need for cyber insurance","D It enables the team to quickly acquire necessary resources during an incident without lengthy approval processes"], correct:3, explanation:"A pre-approved budget removes procurement barriers during time-critical incident response, allowing the team to engage vendors, purchase tools, or hire specialists without delay." },
  { id:10760, domain:4, level:1, question:"Which of the following is the BEST definition of 'crisis management' in the context of information security?", options:["A Annual security awareness training","B Day-to-day IT operations management","C The coordinated effort to manage a major security event that threatens the organization's ability to function, involving senior leadership and broad stakeholder communication","D Routine patch management"], correct:2, explanation:"Crisis management escalates beyond normal incident response to involve executive leadership, broad stakeholder coordination, and strategic decisions when an incident threatens organizational survival or reputation." },
  { id:10761, domain:4, level:2, question:"An organization wants to improve its ability to detect and respond to incidents in cloud environments. Which capability is MOST critical to develop?", options:["A Deploying on-premises appliances in the cloud","B Cloud-native security monitoring using provider APIs and CSPM tools, combined with defined IR procedures for cloud-specific scenarios","C Physical access to cloud data centers","D Avoiding cloud use altogether"], correct:1, explanation:"Cloud environments require cloud-native monitoring approaches and IR procedures specifically designed for the shared responsibility model, API-based access, and ephemeral infrastructure." },
  { id:10762, domain:4, level:2, question:"A security team is building a metrics dashboard for the incident response program. Which metric MOST directly measures containment effectiveness?", options:["A Time from detection to containment (containment time), showing how quickly spread is limited after an incident is identified","B Total IT budget","C Number of security policies in place","D Number of analysts on the team"], correct:0, explanation:"Containment time directly measures how effectively and quickly the team limits incident spread after detection, a key operational metric for IR effectiveness." },
  { id:10763, domain:4, level:2, question:"An organization experiences a credential stuffing attack against its customer portal. What should be the FIRST containment action?", options:["A Increase the server capacity","B Implement rate limiting and CAPTCHA on authentication endpoints, and block attacking IP ranges, while investigating compromised accounts","C Shut down the customer portal permanently","D Notify the press immediately"], correct:1, explanation:"Rate limiting and CAPTCHA disrupt the attack's effectiveness immediately, while IP blocking slows attacker access and account investigation identifies the scope of compromise." },
  { id:10764, domain:4, level:2, question:"Which of the following BEST describes the role of human resources (HR) in insider threat incident response?", options:["A HR supports evidence-based investigation procedures, manages personnel actions consistent with employment law, and ensures the process treats employees fairly and legally","B HR replaces the technical IR team","C HR only manages benefits during incidents","D HR has no role in security incidents"], correct:0, explanation:"HR is critical in insider threat investigations to ensure procedures comply with employment law, support personnel actions, and maintain fairness and consistency." },
  { id:10765, domain:4, level:2, question:"An incident response manager wants to reduce the time to resolve high-severity incidents. Which improvement would have the GREATEST impact?", options:["A Purchasing faster laptops for analysts","B Pre-defining escalation paths, decision authorities, and response playbooks for high-severity scenarios so the team can act without ad hoc decisions","C Adding more printers in the security operations center","D Increasing the frequency of security scans"], correct:1, explanation:"Pre-defined playbooks and clear decision authorities eliminate confusion and delay during high-severity incidents, directly reducing time from detection to resolution." },
  { id:10766, domain:4, level:2, question:"What is the GREATEST risk of not having a defined incident classification scheme?", options:["A Inconsistent prioritization may cause critical incidents to be treated as low priority, leading to inadequate response and extended impact","B Too many incidents will be escalated","C Minor incidents may receive too much attention","D Classification schemes are not useful for security"], correct:0, explanation:"Without a defined scheme, incident severity is assessed ad hoc, risking critical events being under-resourced or delayed while non-critical issues consume response capacity." },
  { id:10767, domain:4, level:2, question:"An organization must maintain a specific certification (e.g., PCI DSS) after a security incident. What should the CISO ensure during recovery?", options:["A That all logs are deleted to protect privacy","B That only the QSA is involved in recovery","C That the certification is suspended indefinitely","D That recovery activities restore compliance posture and that evidence of compliance controls is preserved for the certifying body"], correct:3, explanation:"Recovery must restore not only technical function but also the compliance controls required by the certification, and evidence preservation supports the re-certification process." },
  { id:10768, domain:4, level:2, question:"Which of the following BEST describes the purpose of a disaster recovery test?", options:["A To validate that recovery procedures actually work as expected and meet defined recovery objectives under realistic conditions","B To satisfy an annual audit requirement only","C To update the disaster recovery plan documentation","D To train new employees"], correct:0, explanation:"DR tests validate that procedures, tools, and people can actually achieve recovery within the stated RTO and RPO, revealing gaps that documentation alone cannot expose." },
  { id:10769, domain:4, level:2, question:"An incident responder discovers that an attacker used a legitimate remote management tool (e.g., RMM software) to maintain persistence. Why does this complicate eradication?", options:["A This has no impact on eradication","B RMM tools are always installed by attackers","C Legitimate tools may not be flagged by antivirus, require careful identification to determine what is attacker-controlled versus legitimate, and removal must not disrupt legitimate operations","D RMM tools cannot be removed"], correct:2, explanation:"Attackers using legitimate tools blend in with normal operations; responders must carefully distinguish attacker-controlled instances from legitimate ones before removing them to avoid disrupting real business functions." },
  { id:10770, domain:4, level:2, question:"Which of the following is the MOST important element to include in a post-incident report for senior leadership?", options:["A concise summary of root cause, business impact, actions taken, status, and recommended improvements with resource requirements","B complete timeline of every technical action taken","C list of all IP addresses involved","D Raw firewall logs"], correct:0, explanation:"Senior leadership needs decision-relevant information: what caused it, what it cost, what was done, and what investments are needed to prevent recurrence—not granular technical details." },
  { id:10771, domain:4, level:3, question:"An organization is designing its incident response program for operational technology (OT) and industrial control systems (ICS). How does this differ from traditional IT incident response?", options:["A OT/ICS environments prioritize availability and safety over confidentiality; downtime for containment can cause physical harm, requiring specialized procedures that balance security response with operational continuity","B OT and IT IR are identical","C OT incidents are always handled by the vendor","D OT environments have no cyber risks"], correct:0, explanation:"OT/ICS IR must account for safety-critical systems where improper containment actions can cause physical harm; the safety-first, availability-priority approach fundamentally differs from IT IR." },
  { id:10772, domain:4, level:3, question:"A multinational organization experiences a ransomware attack that encrypts systems in five countries simultaneously. What is the MOST complex challenge in coordinating the response?", options:["A Varying legal obligations, regulatory notification requirements, and response authorities across jurisdictions, combined with the need for simultaneous coordinated technical action","B Time zone differences only","C Differences in hardware vendors","D Language barriers among analysts"], correct:0, explanation:"Multinational incidents require simultaneous adherence to diverse legal and regulatory frameworks while coordinating a unified technical response, creating extreme complexity in decision-making and communication." },
  { id:10773, domain:4, level:3, question:"An organization's threat intelligence team identifies that a nation-state actor is actively targeting organizations in its industry. How should the IR program respond to this intelligence?", options:["A Update detection rules, review existing indicators in the environment, brief leadership on the elevated risk, and enhance monitoring for the actor's known TTPs","B Wait for a government advisory","C Only increase physical security","D Ignore it unless an incident actually occurs"], correct:0, explanation:"Actionable threat intelligence should drive proactive defensive adjustments—updated detection, enhanced monitoring, and leadership awareness—to reduce likelihood and impact before an incident occurs." },
  { id:10774, domain:4, level:3, question:"What is the PRIMARY reason that organizations should conduct 'red team' exercises as part of incident response preparation?", options:["A To test physical security only","B To realistically test detection and response capabilities by simulating sophisticated adversary TTPs in a controlled environment, revealing gaps that cannot be found through other methods","C To satisfy regulatory requirements only","D To replace tabletop exercises"], correct:1, explanation:"Red team exercises simulate real attacker behavior, testing whether actual detection and response capabilities can identify and contain threats that self-assessments and tabletop exercises cannot reveal." },
  { id:10775, domain:4, level:3, question:"An organization's IR team identifies that an attacker has achieved persistence via a rootkit on multiple systems. What makes rootkit eradication particularly challenging?", options:["A Rootkits operate at low system levels (kernel/firmware), can hide from standard tools, and may require reimaging or hardware replacement to fully eradicate","B Rootkits only affect Linux systems","C Rootkits are easily removed with a simple script","D Rootkits are easily detected by standard antivirus"], correct:0, explanation:"Rootkits subvert the operating system or firmware, often hiding from the tools used to remove them, meaning full eradication typically requires wiping and reimaging or, in firmware rootkit cases, hardware replacement." },
  { id:10776, domain:4, level:3, question:"Which of the following BEST explains why incident response programs must address social engineering as a specific attack category?", options:["A Technical controls alone are sufficient to stop social engineering","B Social engineering is only relevant for physical security","C Social engineering bypasses technical controls by targeting human behavior, requiring specific playbooks, user reporting mechanisms, and awareness training as primary defenses","D Social engineering is rare"], correct:2, explanation:"Social engineering exploits human psychology rather than technical vulnerabilities, requiring human-centric detection (user reporting, anomalous behavior monitoring) and response procedures distinct from technical incident types." },
  { id:10777, domain:4, level:3, question:"An organization is evaluating cyber insurance proposals. Which factor is MOST important in assessing whether the policy adequately covers the organization's risk?", options:["A The number of years the insurer has been in business","B The insurer's brand recognition","C The premium cost only","D The policy's coverage limits, sublimits, exclusions, and conditions, assessed against the organization's specific risk profile and most probable loss scenarios"], correct:3, explanation:"Cyber insurance value depends on whether the policy actually covers the organization's most probable and costly scenarios; sublimits and exclusions can render a policy inadequate despite a high headline limit." },
  { id:10778, domain:4, level:3, question:"A company's IR team discovers that an attacker compromised a privileged service account and has been conducting reconnaissance for two months. What is the MOST critical first action in response?", options:["A Notify all employees immediately","B Power off all servers","C Revoke and rotate the compromised credentials, then scope all access and actions taken using the account over the two-month period","D Delete all logs"], correct:2, explanation:"Revoking the compromised credentials immediately stops ongoing attacker access, while thorough scoping of the account's activity over the dwell period is essential to understand the full extent of the breach." },
  { id:10779, domain:4, level:3, question:"An organization wants to implement a threat-informed defense strategy for incident response. What does this approach require?", options:["A Implementing all security controls simultaneously","B Using only the most expensive security tools","C Focusing only on compliance frameworks","D Aligning defensive capabilities and IR procedures to the specific TTPs of threat actors most likely to target the organization, using frameworks like MITRE ATT&CK"], correct:3, explanation:"Threat-informed defense prioritizes security investments and IR procedures based on the specific behaviors of relevant adversaries, maximizing efficiency and effectiveness of defensive measures." },
  { id:10780, domain:4, level:3, question:"What is the MOST significant limitation of using hash-based IoCs in incident response?", options:["A Hash-based IoCs generate too many false positives","B Hash comparison is too slow","C Hashes cannot be computed on modern systems","D Hash-based IoCs are trivially evaded by attackers who make minor modifications to malware, changing the hash while preserving functionality"], correct:3, explanation:"Attackers can change a file's hash with trivial modifications (adding a byte, recompiling), making hash-based IoCs brittle; behavioral and TTP-based detection is more robust." },
  { id:10781, domain:4, level:1, question:"Which of the following BEST defines 'incident response policy'?", options:["A high-level document that establishes management's commitment to incident response, defines scope, roles, and authorities","B software configuration guide","C list of all past security incidents","D technical manual for fixing security incidents"], correct:0, explanation:"An incident response policy sets the organizational foundation—management commitment, scope, roles, and authorities—upon which procedures and playbooks are built." },
  { id:10782, domain:4, level:1, question:"What is the PRIMARY purpose of defining roles and responsibilities in an incident response plan?", options:["A To allocate budget","B To ensure every team member knows their specific function during an incident, preventing confusion and gaps in the response","C To reduce the size of the security team","D To satisfy HR requirements"], correct:1, explanation:"Clearly defined roles eliminate ambiguity during high-stress incidents, ensuring each function (technical, communications, legal, management) is covered and coordinated." },
  { id:10783, domain:4, level:1, question:"What is an 'after-action report' in the context of incident management?", options:["A vendor invoice for IR services","B formal document produced after an incident that summarizes what occurred, how it was handled, and what improvements are recommended","C daily operational status report","D marketing document"], correct:1, explanation:"After-action reports document the incident narrative, response effectiveness, and recommended improvements, serving as the institutional record and improvement driver." },
  { id:10784, domain:4, level:1, question:"Which of the following BEST describes the relationship between RTO and system criticality?", options:["A Less critical systems should have shorter RTOs","B All systems have the same RTO","C RTO does not vary by system","D More critical systems should have shorter RTOs, as their unavailability has greater business impact"], correct:3, explanation:"RTO should reflect business criticality—highly critical systems require faster recovery to minimize operational impact, while less critical systems can tolerate longer recovery windows." },
  { id:10785, domain:4, level:1, question:"Why is documentation important during an active security incident?", options:["A It creates a real-time record of events, actions, and decisions that supports accountability, legal proceedings, and post-incident analysis","B It slows down the response","C It is required by all regulations","D It replaces the need for communication"], correct:0, explanation:"Contemporaneous documentation ensures an accurate chronological record that can be used for investigation, legal purposes, regulatory compliance, and post-incident improvement." },
  { id:10786, domain:4, level:2, question:"An organization's incident response plan specifies that all security incidents must be reported to the CISO within one hour of detection. An analyst detects a confirmed intrusion but waits two hours to report it while investigating further. What is the PRIMARY problem with this approach?", options:["A Delaying notification violates the plan and may cause the CISO to miss critical decisions windows, including regulatory reporting deadlines","B Two hours is an acceptable delay","C Analysts should never investigate incidents","D The analyst should have closed the ticket"], correct:0, explanation:"Notification timelines in IR plans exist to ensure decision-makers are engaged promptly; delays can cascade into missed regulatory deadlines, delayed escalation, and extended incident impact." },
  { id:10787, domain:4, level:2, question:"Which of the following MOST accurately describes the purpose of 'containment strategies' in an IR plan?", options:["A Strategies to permanently fix all security vulnerabilities","B Strategies to replace all affected hardware","C Strategies to communicate the incident publicly","D Pre-defined approaches (short-term and long-term) for limiting the damage and spread of specific incident types, balancing operational continuity with risk reduction"], correct:3, explanation:"Containment strategies provide a range of options—from immediate isolation to temporary controls—balancing the need to limit damage against the operational impact of taking affected systems offline." },
  { id:10788, domain:4, level:2, question:"What is the key advantage of an 'intelligence-led' incident response approach compared to a purely reactive approach?", options:["A It is cheaper than reactive response","B It eliminates all incidents","C It uses knowledge of adversary behavior to proactively position defenses and accelerate detection and response when attacks occur","D It requires no specialized training"], correct:2, explanation:"Intelligence-led IR uses threat actor knowledge to prioritize detection, pre-position defenses, and develop targeted playbooks, enabling faster, more effective responses than purely reactive approaches." },
  { id:10789, domain:4, level:2, question:"A company discovers that its public-facing web application was compromised and customer data was accessed. Which stakeholder group must be notified FIRST in most regulated environments?", options:["A Employees","B The press","C Business partners","D Regulators and/or affected individuals, as required by applicable law, within mandated timeframes"], correct:3, explanation:"Breach notification laws in most jurisdictions mandate timely notification to regulators (e.g., within 72 hours under GDPR) and affected individuals as the primary legal obligation." },
  { id:10790, domain:4, level:2, question:"An organization implements a 'security playbook library' for its SOC. What is the GREATEST benefit of this approach?", options:["A It eliminates the need for skilled analysts","B It eliminates false positives","C It replaces the SIEM","D It ensures consistent, documented, and repeatable responses to known incident types, reducing reliance on individual analyst experience and institutional knowledge"], correct:3, explanation:"Playbook libraries standardize responses across the team, ensure procedures are documented and consistent, and reduce the skill gap impact when experienced analysts are unavailable." },
  { id:10791, domain:4, level:2, question:"Which of the following BEST describes 'digital forensics' in the context of incident response?", options:["A The process of restoring systems after an incident","B The practice of monitoring network traffic","C The scientific collection, preservation, examination, and analysis of digital evidence to reconstruct events and support legal or investigative proceedings","D The practice of destroying evidence"], correct:2, explanation:"Digital forensics applies scientific methodologies to collect, preserve, and analyze digital evidence in a manner that maintains integrity and supports both internal investigation and potential legal proceedings." },
  { id:10792, domain:4, level:2, question:"What is the MOST important factor in selecting a third-party incident response vendor for a retainer?", options:["A The number of vendor employees","B The vendor's office location","C The vendor's website design","D The vendor's demonstrated expertise in the organization's industry, IR capabilities, response time guarantees, and data handling practices"], correct:3, explanation:"A retainer vendor must be assessed on their technical competence, industry expertise, contractual response time commitments, and how they handle the organization's sensitive data during an engagement." },
  { id:10793, domain:4, level:3, question:"A financial institution's IR team discovers that the attacker has been pivoting through the network using valid credentials obtained through a previous phishing campaign. The attacker has access to core banking systems. What is the MOST critical consideration in the containment decision?", options:["A The time of day","B The cost of the response","C The personal preferences of the CISO","D Balancing the need to immediately contain the threat against the regulatory and operational risks of disrupting core banking systems, likely requiring executive and regulatory coordination"], correct:3, explanation:"Core banking systems in regulated environments have strict availability and data integrity requirements; containment decisions must be escalated to executive leadership and may require regulatory notification, making this a governance-level decision, not just a technical one." },
  { id:10794, domain:4, level:3, question:"During incident analysis, the team discovers that the attacker modified audit logs to cover their tracks. What does this MOST significantly impact?", options:["A Physical security of the data center","B The backup restoration process","C The integrity of the forensic record and the ability to fully scope the incident, requiring alternative evidence sources such as network flows, memory forensics, and external logging","D Network performance"], correct:2, explanation:"Tampered logs undermine the primary forensic record; responders must pivot to alternative evidence sources (network flows, immutable external logs, memory forensics) to reconstruct the timeline." },
  { id:10795, domain:4, level:3, question:"An organization has implemented a business continuity program but has not aligned it with its incident response program. What is the PRIMARY risk of this misalignment?", options:["A The programs will cost more to maintain","B During a major cyber incident, the two programs may issue conflicting guidance, causing confusion about whether to prioritize security containment or business continuity operations","C Auditors will penalize the organization","D Employees will be confused about their job duties"], correct:1, explanation:"Misaligned programs can create conflicting priorities during an incident—IR wanting to isolate systems while BCP wants to maintain operations—requiring pre-integration to resolve conflicts before they arise." },
  { id:10796, domain:4, level:3, question:"An organization is developing criteria for when to invoke its business continuity plan following a cyber incident. Which factor is MOST important in defining these criteria?", options:["A Whether the incident is publicly known","B The threshold at which cyber incidents impair critical business functions to a degree that requires alternative operating procedures to maintain minimum service levels","C The size of the IT team","D The season of the year"], correct:1, explanation:"BCP invocation criteria should be tied to business impact—when critical functions can no longer operate at minimum acceptable levels, BCP must be activated regardless of the incident type or cause." },
  { id:10797, domain:4, level:3, question:"A security operations team wants to improve detection of insider threats with access to sensitive customer data. Which approach is MOST effective?", options:["A Requiring managers to monitor employees directly","B Implementing data access monitoring combined with UEBA to baseline normal access patterns and alert on anomalous behavior","C Restricting all remote access","D Blocking all access to customer data"], correct:1, explanation:"Data access monitoring combined with UEBA provides behavioral baselines and anomaly detection that can identify unusual data access patterns indicative of insider threat activity without disrupting legitimate operations." },
  { id:10798, domain:4, level:3, question:"What is the MOST significant advantage of having legal counsel participate in incident response tabletop exercises?", options:["A Legal counsel can fix technical issues","B Exercises are only valid if legal is present","C Legal counsel develops familiarity with IR scenarios and can pre-identify legal issues, privilege considerations, and notification obligations before a real incident creates time pressure","D Legal counsel reduces the cost of exercises"], correct:2, explanation:"Pre-incident legal familiarity ensures that attorneys understand technical IR context and can provide faster, more informed guidance on privilege, obligations, and liability during a real incident." },
  { id:10799, domain:4, level:3, question:"An organization's incident response program lacks defined metrics. What is the MOST significant consequence of this gap?", options:["A The team will be too large","B Management cannot objectively assess program effectiveness, identify trends, justify investments, or demonstrate compliance, leaving the program without accountability or direction for improvement","C Metrics are not needed for mature programs","D Metrics only matter for regulatory compliance"], correct:1, explanation:"Without metrics, IR programs operate without objective measures of effectiveness, making it impossible to demonstrate value, identify deteriorating performance, or make data-driven improvement decisions." },
  { id:10800, domain:4, level:3, question:"A CISO is developing a cyber incident scenario for a board-level tabletop exercise. Which type of scenario would be MOST valuable for testing board-level decision-making?", options:["A high-impact scenario such as a public data breach requiring decisions about notification, media response, regulatory engagement, and business continuity under reputational and financial pressure","B network performance scenario","C technical scenario about firewall rule changes","D routine password reset scenario"], correct:0, explanation:"Board exercises should test governance-level decisions—notification, communication, regulatory engagement, and strategic continuity decisions—not technical details that are below the board's appropriate level of involvement." },
  { id:10801, domain:4, level:1, question:"What is the PRIMARY reason for segregating the incident response team's communication from the compromised network?", options:["A To simplify log management","B To reduce communication costs","C To prevent the attacker from monitoring response activities and adapting their tactics based on the team's actions","D To comply with HR policies"], correct:2, explanation:"If attackers can monitor IR communications, they can adapt their behavior to evade containment; out-of-band communication channels protect the integrity of the response." },
  { id:10802, domain:4, level:1, question:"Which of the following is the MOST basic requirement for effective incident detection?", options:["A Comprehensive logging across critical systems and networks, providing the data needed to identify anomalies and incidents","B Biometric access controls","C 24/7 staffed physical security desk","D dedicated threat intelligence team"], correct:0, explanation:"Without comprehensive logging, there is no data to analyze for incident detection; logging is the foundational requirement that enables all other detection capabilities." },
  { id:10803, domain:4, level:1, question:"What is the purpose of a 'severity level' in incident classification?", options:["A To satisfy insurance requirements","B To indicate the potential impact of an incident and guide the appropriate level of response resources and escalation","C To determine which department caused the incident","D To track the location of the attacker"], correct:1, explanation:"Severity levels provide a standardized way to communicate the urgency and impact of an incident, ensuring that response resources and escalation paths are appropriately matched." },
  { id:10804, domain:4, level:1, question:"Which of the following BEST describes a 'functional exercise' in the context of business continuity testing?", options:["A marketing exercise","B An exercise that only tests IT systems","C document review meeting","D An exercise that activates actual response procedures and resources to simulate a real event, without necessarily involving all components of the organization"], correct:3, explanation:"Functional exercises deploy actual resources and execute real procedures in a simulated scenario, providing a more realistic test than tabletop discussions but without full-scale deployment." },
  { id:10805, domain:4, level:1, question:"Which of the following is NOT a phase in the NIST incident response lifecycle?", options:["A Risk Assessment","B Post-Incident Activity","C Detection and Analysis","D Preparation"], correct:0, explanation:"The NIST IR lifecycle phases are Preparation; Detection and Analysis; Containment, Eradication, and Recovery; and Post-Incident Activity. Risk Assessment is a separate risk management activity, not an IR phase." },
  { id:10806, domain:4, level:2, question:"An organization wants to improve its incident detection capabilities for endpoints. Which technology would provide the GREATEST improvement?", options:["A Endpoint Detection and Response (EDR) solutions that provide behavioral monitoring, threat hunting, and forensic data collection on endpoints","B Antivirus software only","C Network-only monitoring","D Physical security cameras"], correct:0, explanation:"EDR goes beyond signature-based antivirus to provide behavioral monitoring, telemetry collection, and active threat hunting on endpoints, significantly improving detection of sophisticated threats." },
  { id:10807, domain:4, level:2, question:"A security analyst receives an alert that a user has logged in from two different countries within 30 minutes. This is an example of:", options:["A An impossible travel anomaly that is an indicator of potentially compromised credentials requiring immediate investigation","B false positive that can be ignored","C system performance alert","D routine event requiring no action"], correct:0, explanation:"Impossible travel alerts indicate that a user's credentials may be compromised, as legitimate access from two geographically separated locations within an impossible timeframe suggests credential theft." },
  { id:10808, domain:4, level:2, question:"What is the MOST important output of the detection and analysis phase of incident response?", options:["A characterization of the incident including scope, severity, affected systems, and type, sufficient to guide containment decisions","B The identity of the attacker","C The total cost of the incident","D completed remediation plan"], correct:0, explanation:"The detection and analysis phase must produce enough information about the incident's scope, severity, and nature to make informed containment decisions; incomplete analysis leads to ineffective containment." },
  { id:10809, domain:4, level:2, question:"An organization stores sensitive customer data in a cloud environment. During an incident, the IR team requests logs from the cloud provider. Which challenge is MOST likely to arise?", options:["A The cloud provider is responsible for incident response","B Log availability, format, retention periods, and the legal/contractual process for requesting logs may delay access to critical forensic data","C Cloud logs are never useful","D The cloud provider will always provide logs immediately"], correct:1, explanation:"Cloud provider logs may have limited retention, specific formats, and require formal requests through defined processes; organizations should address these access issues contractually before an incident occurs." },
  { id:10810, domain:4, level:2, question:"Which of the following is the BEST reason to conduct incident response exercises at least annually?", options:["A Annual exercises ensure the plan is tested before significant organizational changes (personnel, systems, threats) render it obsolete","B Annual exercises are the cheapest option","C Annual exercises satisfy all regulatory requirements","D Annual exercises are required by insurance"], correct:0, explanation:"Annual exercises ensure the plan is validated against current systems and personnel; more frequent changes may warrant more frequent testing, but annually is a baseline to prevent plans from becoming stale." },
  { id:10811, domain:4, level:3, question:"An organization's response to a major breach has revealed that its legal, communications, and technical teams made conflicting decisions during the first 24 hours. What systemic change would MOST prevent this in the future?", options:["A Separating the teams during future incidents","B Allowing each team to operate independently","C Hiring more lawyers","D Implementing a unified incident command structure with a designated incident commander who has authority to make final decisions and coordinate all teams"], correct:3, explanation:"An incident command structure with a single authoritative coordinator prevents conflicting decisions by providing clear decision authority and forcing cross-team coordination through a unified command." },
  { id:10812, domain:4, level:3, question:"An organization's SIEM generates thousands of alerts daily, but the SOC team investigates fewer than 10%. What is the MOST significant risk of this situation?", options:["A The SIEM is too expensive","B Alert volume is always acceptable","C High-severity incidents may go undetected because they are buried in low-priority alert noise, leading to extended dwell time","D The SOC team is not working hard enough"], correct:2, explanation:"Uninvestigated alerts represent detection gaps; high-severity incidents buried in noise will have extended dwell time, allowing attackers to cause more damage before containment." },
  { id:10813, domain:4, level:3, question:"A CISO is asked to justify the investment in a 24/7 Security Operations Center (SOC) to the board. Which argument is MOST compelling from an incident response perspective?", options:["A SOC is required by all regulations","B Continuous monitoring dramatically reduces MTTD, limiting attacker dwell time and the financial, operational, and reputational damage that increases with each hour of undetected compromise","C SOC eliminates all cyber incidents","D SOC is cheaper than outsourcing all IT"], correct:1, explanation:"The ROI of a SOC is best expressed in terms of dwell time reduction: earlier detection limits breach scope and cost, directly connecting the SOC investment to reduced incident impact." },
  { id:10814, domain:4, level:3, question:"Which of the following represents the MOST mature approach to incident response program governance?", options:["A Outsourcing all IR to a third party","B Having a policy document that is reviewed once every five years","C An IR program with defined objectives, metrics, annual board reporting, continuous improvement processes driven by lessons learned, and alignment with enterprise risk management","D Having a large incident response team"], correct:2, explanation:"True IR governance maturity involves executive accountability, measurable objectives, continuous improvement loops, and integration with enterprise risk management—not just having a team or policy." },
  { id:10815, domain:4, level:3, question:"An organization is building an IR program for a hybrid cloud/on-premises environment. What is the MOST important design consideration?", options:["A Eliminating the on-premises environment","B Treating cloud and on-premises as completely separate programs","C Using the same tools for both environments regardless of compatibility","D Designing IR capabilities that span both environments with unified visibility, consistent procedures, and clear roles for cloud provider versus internal team responsibilities"], correct:3, explanation:"Hybrid environments require integrated IR visibility and procedures that span both environments, with clear delineation of responsibility between the organization and cloud providers." },
  { id:10816, domain:4, level:1, question:"What does 'data exfiltration' mean in the context of security incidents?", options:["A The archiving of old data","B The process of backing up data","C The encryption of data for security purposes","D The unauthorized transfer of sensitive data from an organization to an attacker-controlled location"], correct:3, explanation:"Data exfiltration is a key impact category in security incidents, representing the unauthorized removal of sensitive data, which triggers breach notification, legal, and regulatory consequences." },
  { id:10817, domain:4, level:1, question:"Which of the following is the BEST description of a 'security event'?", options:["A Any software update","B confirmed security incident requiring a formal response","C Only hardware failures","D Any observable occurrence in a system or network that may be relevant to security"], correct:3, explanation:"A security event is any observable occurrence that may have security relevance; not all events are incidents. Events are analyzed to determine whether they constitute incidents requiring a formal response." },
  { id:10818, domain:4, level:1, question:"What is the PRIMARY benefit of having an incident response plan approved by senior management?", options:["A It satisfies annual audit requirements","B It ensures the plan has organizational authority, committed resources, and that all departments understand their obligations to support the response","C It makes the plan longer","D It makes the plan more technical"], correct:1, explanation:"Management approval provides the plan with organizational authority, ensuring that the resources, access, and cross-departmental cooperation required for effective response are pre-authorized." },
  { id:10819, domain:4, level:1, question:"Which of the following BEST describes 'system imaging' in digital forensics?", options:["A Backing up active data only","B Taking a photograph of a server","C Defragmenting a disk for analysis","D Creating a bit-for-bit copy of a storage device to preserve all data, including deleted files and unallocated space, for forensic analysis"], correct:3, explanation:"Forensic imaging creates an exact bit-for-bit copy of the original storage device, preserving all data including deleted files, which is essential for thorough investigation without altering original evidence." },
  { id:10820, domain:4, level:1, question:"What is the KEY purpose of a communication plan within an incident response plan?", options:["A To restrict all communication during an incident","B To manage the organization's social media presence","C To define who communicates what information to which stakeholders, in what format, and through which channels during an incident","D To document all technical findings"], correct:2, explanation:"A communication plan ensures that accurate, timely, and appropriate information flows to the right stakeholders (internal and external) through the right channels, preventing misinformation and omissions." },
  { id:10821, domain:4, level:2, question:"An organization's BCP specifies that 20 key personnel must be able to work remotely during a facility disaster. Which technology capability is MOST critical to validate in a BCP test?", options:["A Physical mail delivery","B Secure remote access (VPN or equivalent) with capacity, performance, and security controls sufficient for the required remote workforce","C The office coffee machine","D The office telephone system only"], correct:1, explanation:"Remote access infrastructure must be validated to ensure it can securely support the specified number of concurrent remote workers with acceptable performance before it is relied upon in a real disaster." },
  { id:10822, domain:4, level:2, question:"Which of the following incident response activities is MOST likely to involve the organization's insurance carrier?", options:["A routine phishing simulation","B major data breach requiring forensic investigation, breach notification, and legal defense, which may trigger first-party and third-party cyber insurance coverage","C minor software vulnerability","D Routine security monitoring"], correct:1, explanation:"Cyber insurance carriers typically become involved in significant incidents with large potential claims—forensic costs, notification, legal defense, and regulatory fines—where they have both financial interest and contractual rights to manage the response." },
  { id:10823, domain:4, level:2, question:"What is the MOST important consideration when deciding to publicly disclose a security incident?", options:["A Whether the CEO approves of the disclosure","B Legal and regulatory obligations, the potential impact on stakeholders, and the risk of greater harm from delayed or inadequate disclosure versus proactive communication","C Whether the incident was embarrassing","D The current stock price"], correct:1, explanation:"Disclosure decisions must be grounded in legal obligations, stakeholder protection, and reputational risk analysis; failure to disclose when legally required creates additional legal liability." },
  { id:10824, domain:4, level:2, question:"A company is reviewing its incident response capabilities after a regulatory change that now requires breach notification within 48 hours. Which gap is MOST likely to require remediation?", options:["A The company's detection capabilities and notification workflows, which must be fast enough to identify, confirm, and notify regulators within 48 hours","B The company's HR policies","C The company's marketing strategy","D The company's physical security posture"], correct:0, explanation:"Tighter notification windows require faster detection, confirmation, and escalation; organizations must ensure their end-to-end process from detection to regulatory notification can fit within the new 48-hour window." },
  { id:10825, domain:4, level:2, question:"An incident responder is asked to determine whether a file found on a compromised system is malicious. Which analysis technique provides the MOST definitive conclusion?", options:["A Dynamic analysis (executing the file in a controlled sandbox environment) to observe actual behavior, supplemented by static analysis of the code","B Counting lines of code","C Checking the file name","D Checking the file size"], correct:0, explanation:"Dynamic analysis in a sandbox reveals actual malicious behavior (network connections, registry modifications, file drops) that static indicators alone may miss, providing the most conclusive determination." },
  { id:10826, domain:4, level:3, question:"An organization is considering implementing automated threat response (e.g., automatically blocking IPs, quarantining hosts) based on SIEM alerts. What is the MOST significant risk to manage?", options:["A Automated responses are too expensive","B False positives may cause legitimate systems or users to be incorrectly blocked, disrupting business operations, requiring careful tuning and human review workflows","C Automated responses always work correctly","D Automated responses are illegal"], correct:1, explanation:"Automated responses amplify both the benefits and risks of detection quality; false positives will automatically disrupt legitimate operations at machine speed, making tuning and human review gates essential." },
  { id:10827, domain:4, level:3, question:"Which of the following BEST describes the concept of 'resilience' in the context of information security and incident management?", options:["A The ability to detect incidents instantly","B The ability to absorb the impact of disruptive events, adapt to new conditions, and return to normal or improved function after an incident","C The ability to prevent all incidents","D The ability to eliminate all vulnerabilities"], correct:1, explanation:"Resilience is the overarching goal of incident management and BCP/DR: organizations that cannot prevent all incidents must be able to absorb, adapt, and recover from them effectively." },
  { id:10828, domain:4, level:3, question:"A CISO is developing a three-year roadmap for the incident response program. Which capability should be prioritized FIRST to provide the greatest improvement in overall program effectiveness?", options:["A Purchasing more security tools","B Improving detection capabilities (MTTD reduction) because all other IR phases depend on timely and accurate detection","C Adding more security staff","D Expanding the BCP program"], correct:1, explanation:"Detection is the triggering capability for all subsequent IR phases; reducing MTTD has a compounding positive effect on all other metrics (MTTR, dwell time, impact) by enabling earlier intervention." },
  { id:10829, domain:4, level:3, question:"During a major incident, the IR team realizes that the attacker has been using legitimate cloud storage services for command and control to evade network detection. What does this technique highlight about detection strategy?", options:["A The cloud provider is responsible for detecting this","B Cloud storage should be banned","C Detection strategies must include behavioral analysis and anomaly detection rather than relying solely on blocklists, as attackers can leverage trusted services to evade signature-based controls","D Standard firewalls are sufficient to detect this"], correct:2, explanation:"Attackers using legitimate services for C2 bypass reputation-based and IP-based blocklists, requiring behavioral detection (unusual data volumes, communication patterns) to identify malicious activity." },
  { id:10830, domain:4, level:3, question:"An organization experiences a major cyber incident and its board requests a formal briefing. What is the MOST important principle to follow when preparing this briefing?", options:["A Present verified facts and known impacts, clearly distinguish what is known from what is uncertain, and focus on business impact, response status, and decisions required from the board","B Delay the briefing until all facts are known","C Include as much technical detail as possible","D Minimize the reported impact to avoid board concern"], correct:0, explanation:"Board briefings must be factually accurate, clearly distinguish certainty from uncertainty, and focus on governance-level items (business impact, key decisions, resource needs) rather than technical minutiae." },
  { id:10831, domain:4, level:1, question:"What is the PRIMARY difference between a security event and a security incident?", options:["A Events are always more serious than incidents","B An event is an observable occurrence that may have security significance, while an incident is an event that has been confirmed to violate or threaten the organization's security posture","C Incidents are always caused by external attackers","D Events are only detected by automated tools"], correct:1, explanation:"All incidents begin as events, but not all events become incidents; the key distinction is that an incident involves a confirmed or credible threat to confidentiality, integrity, or availability." },
  { id:10832, domain:4, level:1, question:"Which of the following BEST describes the purpose of a 'contact list' in an incident response plan?", options:["A list of all employees in the organization","B marketing contact database","C list of all IP addresses","D current, maintained list of key personnel, vendors, regulators, and law enforcement contacts needed during an incident response"], correct:3, explanation:"A current contact list ensures the IR team can quickly reach the right people (internal stakeholders, external vendors, regulators, law enforcement) without searching for contact information during time-critical events." },
  { id:10833, domain:4, level:1, question:"What is the purpose of 'network flow data' (NetFlow) in incident detection and analysis?", options:["A To block malicious traffic","B To encrypt network traffic","C To provide metadata about network communications (source, destination, ports, volumes, timing) that supports detection of anomalous activity and scoping of an incident","D To manage network bandwidth"], correct:2, explanation:"NetFlow data provides visibility into communication patterns and volumes without capturing full packet content, enabling detection of C2 traffic, lateral movement, and data exfiltration even when payloads are encrypted." },
  { id:10834, domain:4, level:1, question:"What is the PRIMARY purpose of conducting a 'gap analysis' for an incident response program?", options:["A To assess network performance","B To satisfy a specific regulatory requirement","C To compare current IR capabilities against desired or required capabilities, identifying areas needing improvement","D To identify which employees to terminate"], correct:2, explanation:"A gap analysis identifies the delta between current and target IR capabilities, providing a prioritized list of improvements needed to meet defined standards or address identified risks." },
  { id:10835, domain:4, level:2, question:"An organization's incident response team identifies that a ransomware infection began with an unpatched vulnerability in a remote desktop protocol (RDP) service exposed to the internet. Which preventive control failure does this MOST directly indicate?", options:["A Insufficient backup procedures","B combination of inadequate vulnerability management and poor network exposure management, allowing an exploitable service to remain internet-accessible while unpatched","C Insufficient logging","D failure in the incident response plan"], correct:1, explanation:"The incident reflects dual failures: vulnerability management (the patch was not applied timely) and attack surface management (RDP was unnecessarily exposed to the internet), both of which must be addressed." },
  { id:10836, domain:4, level:2, question:"Which of the following approaches BEST supports continuous improvement of incident response capabilities?", options:["A Increasing the budget annually","B Systematically reviewing all post-incident lessons learned, tracking action items to completion, and incorporating improvements into playbooks and controls before the next incident","C Maintaining the same procedures year after year","D Hiring more external consultants each year"], correct:1, explanation:"Continuous improvement requires a closed loop: capturing lessons, generating actionable improvements, implementing them, and measuring the effect—not just documenting lessons and moving on." },
  { id:10837, domain:4, level:2, question:"An organization's incident response plan was written three years ago and has not been updated. During an incident, the team discovers that several key contacts have left the organization and two critical systems referenced in the plan no longer exist. What should the CISM recommend to prevent this situation?", options:["A Establish a formal review cycle (at least annually) and link the plan to change management processes so updates are triggered by significant organizational or system changes","B Train employees to ignore outdated procedures","C Create a new plan after every incident","D Remove all specific references to systems and people from the plan"], correct:0, explanation:"Plans must be kept current through scheduled reviews and change management integration; tying plan updates to organizational change events ensures accuracy between annual review cycles." },
  { id:10838, domain:4, level:3, question:"An organization's legal team advises that all incident response communications should be routed through legal counsel to preserve attorney-client privilege. What is the PRIMARY benefit of this approach?", options:["A It slows down the incident response","B Sensitive communications about the incident may be protected from discovery in legal proceedings, reducing litigation risk","C It reduces the cost of the response","D It eliminates the need for post-incident review"], correct:1, explanation:"Routing IR communications through legal counsel may attach attorney-client privilege to sensitive assessments and analyses, potentially protecting them from disclosure in subsequent litigation or regulatory proceedings." },
  { id:10839, domain:4, level:3, question:"A CISO wants to ensure that the organization's incident response program adequately addresses the risk of a major cloud service provider outage. Which BCP element is MOST important to establish?", options:["A list of all cloud services used","B policy prohibiting cloud service usage","C plan to eliminate all cloud usage","D provider dependency analysis identifying critical cloud services, with defined fallback procedures and RTO/RPO for each service in the event of provider disruption"], correct:3, explanation:"Cloud provider dependency analysis enables the organization to understand the business impact of specific provider outages and design appropriate continuity measures, fallback procedures, and recovery objectives for each critical cloud service." },
  { id:10840, domain:4, level:3, question:"An information security manager is reviewing the organization's incident response metrics over the past year and notes that while MTTD has improved significantly, MTTR has remained unchanged. What does this MOST likely indicate?", options:["A MTTR is not an important metric","B The incident response program is fully mature","C Detection improvements are not translating to faster response; the bottleneck has shifted to the response and recovery phases, suggesting that containment, eradication, or recovery procedures need improvement","D The organization should reduce detection investment"], correct:2, explanation:"When detection improves but recovery time stagnates, the bottleneck has moved downstream to containment, eradication, or recovery processes; the improvement program must now focus on accelerating these phases." }
];
if (typeof window !== 'undefined') window.QUESTIONS_CISM_C4 = QUESTIONS_CISM_C4;
